window.BIBLE["1Timothy"] = {"1":{"chapter":"1","title":"1 Timothy 1","verses":{"1":{"text":"Paul, an apostle of Jesus Christ by the commandment of God our Saviour, and Lord Jesus Christ, which is our hope;","ref":"1 Timothy 1:1","synthesized":"Paul, an apostle of Jesus Christ by the commandment of God our Saviour, and Lord Jesus Christ, which is our hope;","sources":{"KJV":{"text":"Paul, an apostle of Jesus Christ by the commandment of God our Saviour, and Lord Jesus Christ, which is our hope;"}},"definableWords":[],"peopleInVerse":[]},"2":{"text":"Unto Timothy, my own son in the faith: Grace, mercy, and peace, from God our Father and Jesus Christ our Lord.","ref":"1 Timothy 1:2","synthesized":"Unto Timothy, my own son in the faith: Grace, mercy, and peace, from God our Father and Jesus Christ our Lord.","sources":{"KJV":{"text":"Unto Timothy, my own son in the faith: Grace, mercy, and peace, from God our Father and Jesus Christ our Lord."}},"definableWords":[],"peopleInVerse":[]},"3":{"text":"As I besought thee to abide still at Ephesus, when I went into Macedonia, that thou mightest charge some that they teach no other doctrine,","ref":"1 Timothy 1:3","synthesized":"As I besought thee to abide still at Ephesus, when I went into Macedonia, that thou mightest charge some that they teach no other doctrine,","sources":{"KJV":{"text":"As I besought thee to abide still at Ephesus, when I went into Macedonia, that thou mightest charge some that they teach no other doctrine,"}},"definableWords":[],"peopleInVerse":[]},"4":{"text":"Neither give heed to fables and endless genealogies, which minister questions, rather than godly edifying which is in faith: so do.","ref":"1 Timothy 1:4","synthesized":"Neither give heed to fables and endless genealogies, which minister questions, rather than godly edifying which is in faith: so do.","sources":{"KJV":{"text":"Neither give heed to fables and endless genealogies, which minister questions, rather than godly edifying which is in faith: so do."}},"definableWords":[],"peopleInVerse":[]},"5":{"text":"Now the end of the commandment is charity out of a pure heart, and of a good conscience, and of faith unfeigned:","ref":"1 Timothy 1:5","synthesized":"Now the end of the commandment is charity out of a pure heart, and of a good conscience, and of faith unfeigned:","sources":{"KJV":{"text":"Now the end of the commandment is charity out of a pure heart, and of a good conscience, and of faith unfeigned:"}},"definableWords":[],"peopleInVerse":[]},"6":{"text":"From which some having swerved have turned aside unto vain jangling;","ref":"1 Timothy 1:6","synthesized":"From which some having swerved have turned aside unto vain jangling;","sources":{"KJV":{"text":"From which some having swerved have turned aside unto vain jangling;"}},"definableWords":[],"peopleInVerse":[]},"7":{"text":"Desiring to be teachers of the law; understanding neither what they say, nor whereof they affirm.","ref":"1 Timothy 1:7","synthesized":"Desiring to be teachers of the law; understanding neither what they say, nor whereof they affirm.","sources":{"KJV":{"text":"Desiring to be teachers of the law; understanding neither what they say, nor whereof they affirm."}},"definableWords":[],"peopleInVerse":[]},"8":{"text":"But we know that the law is good, if a man use it lawfully;","ref":"1 Timothy 1:8","synthesized":"But we know that the law is good, if a man use it lawfully;","sources":{"KJV":{"text":"But we know that the law is good, if a man use it lawfully;"}},"definableWords":[],"peopleInVerse":[]},"9":{"text":"Knowing this, that the law is not made for a righteous man, but for the lawless and disobedient, for the ungodly and for sinners, for unholy and profane, for murderers of fathers and murderers of mothers, for manslayers,","ref":"1 Timothy 1:9","synthesized":"Knowing this, that the law is not made for a righteous man, but for the lawless and disobedient, for the ungodly and for sinners, for unholy and profane, for murderers of fathers and murderers of mothers, for manslayers,","sources":{"KJV":{"text":"Knowing this, that the law is not made for a righteous man, but for the lawless and disobedient, for the ungodly and for sinners, for unholy and profane, for murderers of fathers and murderers of mothers, for manslayers,"}},"definableWords":[],"peopleInVerse":[]},"10":{"text":"For whoremongers, for them that defile themselves with mankind, for menstealers, for liars, for perjured persons, and if there be any other thing that is contrary to sound doctrine;","ref":"1 Timothy 1:10","synthesized":"For whoremongers, for them that defile themselves with mankind, for menstealers, for liars, for perjured persons, and if there be any other thing that is contrary to sound doctrine;","sources":{"KJV":{"text":"For whoremongers, for them that defile themselves with mankind, for menstealers, for liars, for perjured persons, and if there be any other thing that is contrary to sound doctrine;"}},"definableWords":[],"peopleInVerse":[]},"11":{"text":"According to the glorious gospel of the blessed God, which was committed to my trust.","ref":"1 Timothy 1:11","synthesized":"According to the glorious gospel of the blessed God, which was committed to my trust.","sources":{"KJV":{"text":"According to the glorious gospel of the blessed God, which was committed to my trust."}},"definableWords":[],"peopleInVerse":[]},"12":{"text":"And I thank Christ Jesus our Lord, who hath enabled me, for that he counted me faithful, putting me into the ministry;","ref":"1 Timothy 1:12","synthesized":"And I thank Christ Jesus our Lord, who hath enabled me, for that he counted me faithful, putting me into the ministry;","sources":{"KJV":{"text":"And I thank Christ Jesus our Lord, who hath enabled me, for that he counted me faithful, putting me into the ministry;"}},"definableWords":[],"peopleInVerse":[]},"13":{"text":"Who was before a blasphemer, and a persecutor, and injurious: but I obtained mercy, because I did it ignorantly in unbelief.","ref":"1 Timothy 1:13","synthesized":"Who was before a blasphemer, and a persecutor, and injurious: but I obtained mercy, because I did it ignorantly in unbelief.","sources":{"KJV":{"text":"Who was before a blasphemer, and a persecutor, and injurious: but I obtained mercy, because I did it ignorantly in unbelief."}},"definableWords":[],"peopleInVerse":[]},"14":{"text":"And the grace of our Lord was exceeding abundant with faith and love which is in Christ Jesus.","ref":"1 Timothy 1:14","synthesized":"And the grace of our Lord was exceeding abundant with faith and love which is in Christ Jesus.","sources":{"KJV":{"text":"And the grace of our Lord was exceeding abundant with faith and love which is in Christ Jesus."}},"definableWords":[],"peopleInVerse":[]},"15":{"text":"This is a faithful saying, and worthy of all acceptation, that Christ Jesus came into the world to save sinners; of whom I am chief.","ref":"1 Timothy 1:15","synthesized":"This is a faithful saying, and worthy of all acceptation, that Christ Jesus came into the world to save sinners; of whom I am chief.","sources":{"KJV":{"text":"This is a faithful saying, and worthy of all acceptation, that Christ Jesus came into the world to save sinners; of whom I am chief."}},"definableWords":[],"peopleInVerse":[]},"16":{"text":"Howbeit for this cause I obtained mercy, that in me first Jesus Christ might shew forth all longsuffering, for a pattern to them which should hereafter believe on him to life everlasting.","ref":"1 Timothy 1:16","synthesized":"Howbeit for this cause I obtained mercy, that in me first Jesus Christ might shew forth all longsuffering, for a pattern to them which should hereafter believe on him to life everlasting.","sources":{"KJV":{"text":"Howbeit for this cause I obtained mercy, that in me first Jesus Christ might shew forth all longsuffering, for a pattern to them which should hereafter believe on him to life everlasting."}},"definableWords":[],"peopleInVerse":[]},"17":{"text":"Now unto the King eternal, immortal, invisible, the only wise God, be honour and glory for ever and ever. Amen.","ref":"1 Timothy 1:17","synthesized":"Now unto the King eternal, immortal, invisible, the only wise God, be honour and glory for ever and ever. Amen.","sources":{"KJV":{"text":"Now unto the King eternal, immortal, invisible, the only wise God, be honour and glory for ever and ever. Amen."}},"definableWords":[],"peopleInVerse":[]},"18":{"text":"This charge I commit unto thee, son Timothy, according to the prophecies which went before on thee, that thou by them mightest war a good warfare;","ref":"1 Timothy 1:18","synthesized":"This charge I commit unto thee, son Timothy, according to the prophecies which went before on thee, that thou by them mightest war a good warfare;","sources":{"KJV":{"text":"This charge I commit unto thee, son Timothy, according to the prophecies which went before on thee, that thou by them mightest war a good warfare;"}},"definableWords":[],"peopleInVerse":[]},"19":{"text":"Holding faith, and a good conscience; which some having put away concerning faith have made shipwreck:","ref":"1 Timothy 1:19","synthesized":"Holding faith, and a good conscience; which some having put away concerning faith have made shipwreck:","sources":{"KJV":{"text":"Holding faith, and a good conscience; which some having put away concerning faith have made shipwreck:"}},"definableWords":[],"peopleInVerse":[]},"20":{"text":"Of whom is Hymenaeus and Alexander; whom I have delivered unto Satan, that they may learn not to blaspheme.","ref":"1 Timothy 1:20","synthesized":"Of whom is Hymenaeus and Alexander; whom I have delivered unto Satan, that they may learn not to blaspheme.","sources":{"KJV":{"text":"Of whom is Hymenaeus and Alexander; whom I have delivered unto Satan, that they may learn not to blaspheme."}},"definableWords":[],"peopleInVerse":[]}}},"2":{"chapter":"2","title":"1 Timothy 2","verses":{"1":{"text":"I exhort therefore, that, first of all, supplications, prayers, intercessions, and giving of thanks, be made for all men;","ref":"1 Timothy 2:1","synthesized":"I exhort therefore, that, first of all, supplications, prayers, intercessions, and giving of thanks, be made for all men;","sources":{"KJV":{"text":"I exhort therefore, that, first of all, supplications, prayers, intercessions, and giving of thanks, be made for all men;"}},"definableWords":[],"peopleInVerse":[]},"2":{"text":"For kings, and for all that are in authority; that we may lead a quiet and peaceable life in all godliness and honesty.","ref":"1 Timothy 2:2","synthesized":"For kings, and for all that are in authority; that we may lead a quiet and peaceable life in all godliness and honesty.","sources":{"KJV":{"text":"For kings, and for all that are in authority; that we may lead a quiet and peaceable life in all godliness and honesty."}},"definableWords":[],"peopleInVerse":[]},"3":{"text":"For this is good and acceptable in the sight of God our Saviour;","ref":"1 Timothy 2:3","synthesized":"For this is good and acceptable in the sight of God our Saviour;","sources":{"KJV":{"text":"For this is good and acceptable in the sight of God our Saviour;"}},"definableWords":[],"peopleInVerse":[]},"4":{"text":"Who will have all men to be saved, and to come unto the knowledge of the truth.","ref":"1 Timothy 2:4","synthesized":"Who will have all men to be saved, and to come unto the knowledge of the truth.","sources":{"KJV":{"text":"Who will have all men to be saved, and to come unto the knowledge of the truth."}},"definableWords":[],"peopleInVerse":[]},"5":{"text":"For there is one God, and one mediator between God and men, the man Christ Jesus;","ref":"1 Timothy 2:5","synthesized":"For there is one God, and one mediator between God and men, the man Christ Jesus;","sources":{"KJV":{"text":"For there is one God, and one mediator between God and men, the man Christ Jesus;"}},"definableWords":[],"peopleInVerse":[]},"6":{"text":"Who gave himself a ransom for all, to be testified in due time.","ref":"1 Timothy 2:6","synthesized":"Who gave himself a ransom for all, to be testified in due time.","sources":{"KJV":{"text":"Who gave himself a ransom for all, to be testified in due time."}},"definableWords":[],"peopleInVerse":[]},"7":{"text":"Whereunto I am ordained a preacher, and an apostle, (I speak the truth in Christ, and lie not;) a teacher of the Gentiles in faith and verity.","ref":"1 Timothy 2:7","synthesized":"Whereunto I am ordained a preacher, and an apostle, (I speak the truth in Christ, and lie not;) a teacher of the Gentiles in faith and verity.","sources":{"KJV":{"text":"Whereunto I am ordained a preacher, and an apostle, (I speak the truth in Christ, and lie not;) a teacher of the Gentiles in faith and verity."}},"definableWords":[],"peopleInVerse":[]},"8":{"text":"I will therefore that men pray every where, lifting up holy hands, without wrath and doubting.","ref":"1 Timothy 2:8","synthesized":"I will therefore that men pray every where, lifting up holy hands, without wrath and doubting.","sources":{"KJV":{"text":"I will therefore that men pray every where, lifting up holy hands, without wrath and doubting."}},"definableWords":[],"peopleInVerse":[]},"9":{"text":"In like manner also, that women adorn themselves in modest apparel, with shamefacedness and sobriety; not with broided hair, or gold, or pearls, or costly array;","ref":"1 Timothy 2:9","synthesized":"In like manner also, that women adorn themselves in modest apparel, with shamefacedness and sobriety; not with broided hair, or gold, or pearls, or costly array;","sources":{"KJV":{"text":"In like manner also, that women adorn themselves in modest apparel, with shamefacedness and sobriety; not with broided hair, or gold, or pearls, or costly array;"}},"definableWords":[],"peopleInVerse":[]},"10":{"text":"But (which becometh women professing godliness) with good works.","ref":"1 Timothy 2:10","synthesized":"But (which becometh women professing godliness) with good works.","sources":{"KJV":{"text":"But (which becometh women professing godliness) with good works."}},"definableWords":[],"peopleInVerse":[]},"11":{"text":"Let the woman learn in silence with all subjection.","ref":"1 Timothy 2:11","synthesized":"Let the woman learn in silence with all subjection.","sources":{"KJV":{"text":"Let the woman learn in silence with all subjection."}},"definableWords":[],"peopleInVerse":[]},"12":{"text":"But I suffer not a woman to teach, nor to usurp authority over the man, but to be in silence.","ref":"1 Timothy 2:12","synthesized":"But I suffer not a woman to teach, nor to usurp authority over the man, but to be in silence.","sources":{"KJV":{"text":"But I suffer not a woman to teach, nor to usurp authority over the man, but to be in silence."}},"definableWords":[],"peopleInVerse":[]},"13":{"text":"For Adam was first formed, then Eve.","ref":"1 Timothy 2:13","synthesized":"For Adam was first formed, then Eve.","sources":{"KJV":{"text":"For Adam was first formed, then Eve."}},"definableWords":[],"peopleInVerse":[]},"14":{"text":"And Adam was not deceived, but the woman being deceived was in the transgression.","ref":"1 Timothy 2:14","synthesized":"And Adam was not deceived, but the woman being deceived was in the transgression.","sources":{"KJV":{"text":"And Adam was not deceived, but the woman being deceived was in the transgression."}},"definableWords":[],"peopleInVerse":[]},"15":{"text":"Notwithstanding she shall be saved in childbearing, if they continue in faith and charity and holiness with sobriety.","ref":"1 Timothy 2:15","synthesized":"Notwithstanding she shall be saved in childbearing, if they continue in faith and charity and holiness with sobriety.","sources":{"KJV":{"text":"Notwithstanding she shall be saved in childbearing, if they continue in faith and charity and holiness with sobriety."}},"definableWords":[],"peopleInVerse":[]}}},"3":{"chapter":"3","title":"1 Timothy 3","verses":{"1":{"text":"This is a true saying, If a man desire the office of a bishop, he desireth a good work.","ref":"1 Timothy 3:1","synthesized":"This is a true saying, If a man desire the office of a bishop, he desireth a good work.","sources":{"KJV":{"text":"This is a true saying, If a man desire the office of a bishop, he desireth a good work."}},"definableWords":[],"peopleInVerse":[]},"2":{"text":"A bishop then must be blameless, the husband of one wife, vigilant, sober, of good behaviour, given to hospitality, apt to teach;","ref":"1 Timothy 3:2","synthesized":"A bishop then must be blameless, the husband of one wife, vigilant, sober, of good behaviour, given to hospitality, apt to teach;","sources":{"KJV":{"text":"A bishop then must be blameless, the husband of one wife, vigilant, sober, of good behaviour, given to hospitality, apt to teach;"}},"definableWords":[],"peopleInVerse":[]},"3":{"text":"Not given to wine, no striker, not greedy of filthy lucre; but patient, not a brawler, not covetous;","ref":"1 Timothy 3:3","synthesized":"Not given to wine, no striker, not greedy of filthy lucre; but patient, not a brawler, not covetous;","sources":{"KJV":{"text":"Not given to wine, no striker, not greedy of filthy lucre; but patient, not a brawler, not covetous;"}},"definableWords":[],"peopleInVerse":[]},"4":{"text":"One that ruleth well his own house, having his children in subjection with all gravity;","ref":"1 Timothy 3:4","synthesized":"One that ruleth well his own house, having his children in subjection with all gravity;","sources":{"KJV":{"text":"One that ruleth well his own house, having his children in subjection with all gravity;"}},"definableWords":[],"peopleInVerse":[]},"5":{"text":"(For if a man know not how to rule his own house, how shall he take care of the church of God?)","ref":"1 Timothy 3:5","synthesized":"(For if a man know not how to rule his own house, how shall he take care of the church of God?)","sources":{"KJV":{"text":"(For if a man know not how to rule his own house, how shall he take care of the church of God?)"}},"definableWords":[],"peopleInVerse":[]},"6":{"text":"Not a novice, lest being lifted up with pride he fall into the condemnation of the devil.","ref":"1 Timothy 3:6","synthesized":"Not a novice, lest being lifted up with pride he fall into the condemnation of the devil.","sources":{"KJV":{"text":"Not a novice, lest being lifted up with pride he fall into the condemnation of the devil."}},"definableWords":[],"peopleInVerse":[]},"7":{"text":"Moreover he must have a good report of them which are without; lest he fall into reproach and the snare of the devil.","ref":"1 Timothy 3:7","synthesized":"Moreover he must have a good report of them which are without; lest he fall into reproach and the snare of the devil.","sources":{"KJV":{"text":"Moreover he must have a good report of them which are without; lest he fall into reproach and the snare of the devil."}},"definableWords":[],"peopleInVerse":[]},"8":{"text":"Likewise must the deacons be grave, not doubletongued, not given to much wine, not greedy of filthy lucre;","ref":"1 Timothy 3:8","synthesized":"Likewise must the deacons be grave, not doubletongued, not given to much wine, not greedy of filthy lucre;","sources":{"KJV":{"text":"Likewise must the deacons be grave, not doubletongued, not given to much wine, not greedy of filthy lucre;"}},"definableWords":[],"peopleInVerse":[]},"9":{"text":"Holding the mystery of the faith in a pure conscience.","ref":"1 Timothy 3:9","synthesized":"Holding the mystery of the faith in a pure conscience.","sources":{"KJV":{"text":"Holding the mystery of the faith in a pure conscience."}},"definableWords":[],"peopleInVerse":[]},"10":{"text":"And let these also first be proved; then let them use the office of a deacon, being found blameless.","ref":"1 Timothy 3:10","synthesized":"And let these also first be proved; then let them use the office of a deacon, being found blameless.","sources":{"KJV":{"text":"And let these also first be proved; then let them use the office of a deacon, being found blameless."}},"definableWords":[],"peopleInVerse":[]},"11":{"text":"Even so must their wives be grave, not slanderers, sober, faithful in all things.","ref":"1 Timothy 3:11","synthesized":"Even so must their wives be grave, not slanderers, sober, faithful in all things.","sources":{"KJV":{"text":"Even so must their wives be grave, not slanderers, sober, faithful in all things."}},"definableWords":[],"peopleInVerse":[]},"12":{"text":"Let the deacons be the husbands of one wife, ruling their children and their own houses well.","ref":"1 Timothy 3:12","synthesized":"Let the deacons be the husbands of one wife, ruling their children and their own houses well.","sources":{"KJV":{"text":"Let the deacons be the husbands of one wife, ruling their children and their own houses well."}},"definableWords":[],"peopleInVerse":[]},"13":{"text":"For they that have used the office of a deacon well purchase to themselves a good degree, and great boldness in the faith which is in Christ Jesus.","ref":"1 Timothy 3:13","synthesized":"For they that have used the office of a deacon well purchase to themselves a good degree, and great boldness in the faith which is in Christ Jesus.","sources":{"KJV":{"text":"For they that have used the office of a deacon well purchase to themselves a good degree, and great boldness in the faith which is in Christ Jesus."}},"definableWords":[],"peopleInVerse":[]},"14":{"text":"These things write I unto thee, hoping to come unto thee shortly:","ref":"1 Timothy 3:14","synthesized":"These things write I unto thee, hoping to come unto thee shortly:","sources":{"KJV":{"text":"These things write I unto thee, hoping to come unto thee shortly:"}},"definableWords":[],"peopleInVerse":[]},"15":{"text":"But if I tarry long, that thou mayest know how thou oughtest to behave thyself in the house of God, which is the church of the living God, the pillar and ground of the truth.","ref":"1 Timothy 3:15","synthesized":"But if I tarry long, that thou mayest know how thou oughtest to behave thyself in the house of God, which is the church of the living God, the pillar and ground of the truth.","sources":{"KJV":{"text":"But if I tarry long, that thou mayest know how thou oughtest to behave thyself in the house of God, which is the church of the living God, the pillar and ground of the truth."}},"definableWords":[],"peopleInVerse":[]},"16":{"text":"And without controversy great is the mystery of godliness: God was manifest in the flesh, justified in the Spirit, seen of angels, preached unto the Gentiles, believed on in the world, received up into glory.","ref":"1 Timothy 3:16","synthesized":"And without controversy great is the mystery of godliness: God was manifest in the flesh, justified in the Spirit, seen of angels, preached unto the Gentiles, believed on in the world, received up into glory.","sources":{"KJV":{"text":"And without controversy great is the mystery of godliness: God was manifest in the flesh, justified in the Spirit, seen of angels, preached unto the Gentiles, believed on in the world, received up into glory."}},"definableWords":[],"peopleInVerse":[]}}},"4":{"chapter":"4","title":"1 Timothy 4","verses":{"1":{"text":"Now the Spirit speaketh expressly, that in the latter times some shall depart from the faith, giving heed to seducing spirits, and doctrines of devils;","ref":"1 Timothy 4:1","synthesized":"Now the Spirit speaketh expressly, that in the latter times some shall depart from the faith, giving heed to seducing spirits, and doctrines of devils;","sources":{"KJV":{"text":"Now the Spirit speaketh expressly, that in the latter times some shall depart from the faith, giving heed to seducing spirits, and doctrines of devils;"}},"definableWords":[],"peopleInVerse":[]},"2":{"text":"Speaking lies in hypocrisy; having their conscience seared with a hot iron;","ref":"1 Timothy 4:2","synthesized":"Speaking lies in hypocrisy; having their conscience seared with a hot iron;","sources":{"KJV":{"text":"Speaking lies in hypocrisy; having their conscience seared with a hot iron;"}},"definableWords":[],"peopleInVerse":[]},"3":{"text":"Forbidding to marry, and commanding to abstain from meats, which God hath created to be received with thanksgiving of them which believe and know the truth.","ref":"1 Timothy 4:3","synthesized":"Forbidding to marry, and commanding to abstain from meats, which God hath created to be received with thanksgiving of them which believe and know the truth.","sources":{"KJV":{"text":"Forbidding to marry, and commanding to abstain from meats, which God hath created to be received with thanksgiving of them which believe and know the truth."}},"definableWords":[],"peopleInVerse":[]},"4":{"text":"For every creature of God is good, and nothing to be refused, if it be received with thanksgiving:","ref":"1 Timothy 4:4","synthesized":"For every creature of God is good, and nothing to be refused, if it be received with thanksgiving:","sources":{"KJV":{"text":"For every creature of God is good, and nothing to be refused, if it be received with thanksgiving:"}},"definableWords":[],"peopleInVerse":[]},"5":{"text":"For it is sanctified by the word of God and prayer.","ref":"1 Timothy 4:5","synthesized":"For it is sanctified by the word of God and prayer.","sources":{"KJV":{"text":"For it is sanctified by the word of God and prayer."}},"definableWords":[],"peopleInVerse":[]},"6":{"text":"If thou put the brethren in remembrance of these things, thou shalt be a good minister of Jesus Christ, nourished up in the words of faith and of good doctrine, whereunto thou hast attained.","ref":"1 Timothy 4:6","synthesized":"If thou put the brethren in remembrance of these things, thou shalt be a good minister of Jesus Christ, nourished up in the words of faith and of good doctrine, whereunto thou hast attained.","sources":{"KJV":{"text":"If thou put the brethren in remembrance of these things, thou shalt be a good minister of Jesus Christ, nourished up in the words of faith and of good doctrine, whereunto thou hast attained."}},"definableWords":[],"peopleInVerse":[]},"7":{"text":"But refuse profane and old wives’ fables, and exercise thyself rather unto godliness.","ref":"1 Timothy 4:7","synthesized":"But refuse profane and old wives’ fables, and exercise thyself rather unto godliness.","sources":{"KJV":{"text":"But refuse profane and old wives’ fables, and exercise thyself rather unto godliness."}},"definableWords":[],"peopleInVerse":[]},"8":{"text":"For bodily exercise profiteth little: but godliness is profitable unto all things, having promise of the life that now is, and of that which is to come.","ref":"1 Timothy 4:8","synthesized":"For bodily exercise profiteth little: but godliness is profitable unto all things, having promise of the life that now is, and of that which is to come.","sources":{"KJV":{"text":"For bodily exercise profiteth little: but godliness is profitable unto all things, having promise of the life that now is, and of that which is to come."}},"definableWords":[],"peopleInVerse":[]},"9":{"text":"This is a faithful saying and worthy of all acceptation.","ref":"1 Timothy 4:9","synthesized":"This is a faithful saying and worthy of all acceptation.","sources":{"KJV":{"text":"This is a faithful saying and worthy of all acceptation."}},"definableWords":[],"peopleInVerse":[]},"10":{"text":"For therefore we both labour and suffer reproach, because we trust in the living God, who is the Saviour of all men, specially of those that believe.","ref":"1 Timothy 4:10","synthesized":"For therefore we both labour and suffer reproach, because we trust in the living God, who is the Saviour of all men, specially of those that believe.","sources":{"KJV":{"text":"For therefore we both labour and suffer reproach, because we trust in the living God, who is the Saviour of all men, specially of those that believe."}},"definableWords":[],"peopleInVerse":[]},"11":{"text":"These things command and teach.","ref":"1 Timothy 4:11","synthesized":"These things command and teach.","sources":{"KJV":{"text":"These things command and teach."}},"definableWords":[],"peopleInVerse":[]},"12":{"text":"Let no man despise thy youth; but be thou an example of the believers, in word, in conversation, in charity, in spirit, in faith, in purity.","ref":"1 Timothy 4:12","synthesized":"Let no man despise thy youth; but be thou an example of the believers, in word, in conversation, in charity, in spirit, in faith, in purity.","sources":{"KJV":{"text":"Let no man despise thy youth; but be thou an example of the believers, in word, in conversation, in charity, in spirit, in faith, in purity."}},"definableWords":[],"peopleInVerse":[]},"13":{"text":"Till I come, give attendance to reading, to exhortation, to doctrine.","ref":"1 Timothy 4:13","synthesized":"Till I come, give attendance to reading, to exhortation, to doctrine.","sources":{"KJV":{"text":"Till I come, give attendance to reading, to exhortation, to doctrine."}},"definableWords":[],"peopleInVerse":[]},"14":{"text":"Neglect not the gift that is in thee, which was given thee by prophecy, with the laying on of the hands of the presbytery.","ref":"1 Timothy 4:14","synthesized":"Neglect not the gift that is in thee, which was given thee by prophecy, with the laying on of the hands of the presbytery.","sources":{"KJV":{"text":"Neglect not the gift that is in thee, which was given thee by prophecy, with the laying on of the hands of the presbytery."}},"definableWords":[],"peopleInVerse":[]},"15":{"text":"Meditate upon these things; give thyself wholly to them; that thy profiting may appear to all.","ref":"1 Timothy 4:15","synthesized":"Meditate upon these things; give thyself wholly to them; that thy profiting may appear to all.","sources":{"KJV":{"text":"Meditate upon these things; give thyself wholly to them; that thy profiting may appear to all."}},"definableWords":[],"peopleInVerse":[]},"16":{"text":"Take heed unto thyself, and unto the doctrine; continue in them: for in doing this thou shalt both save thyself, and them that hear thee.","ref":"1 Timothy 4:16","synthesized":"Take heed unto thyself, and unto the doctrine; continue in them: for in doing this thou shalt both save thyself, and them that hear thee.","sources":{"KJV":{"text":"Take heed unto thyself, and unto the doctrine; continue in them: for in doing this thou shalt both save thyself, and them that hear thee."}},"definableWords":[],"peopleInVerse":[]}}},"5":{"chapter":"5","title":"1 Timothy 5","verses":{"1":{"text":"Rebuke not an elder, but intreat him as a father; and the younger men as brethren;","ref":"1 Timothy 5:1","synthesized":"Rebuke not an elder, but intreat him as a father; and the younger men as brethren;","sources":{"KJV":{"text":"Rebuke not an elder, but intreat him as a father; and the younger men as brethren;"}},"definableWords":[],"peopleInVerse":[]},"2":{"text":"The elder women as mothers; the younger as sisters, with all purity.","ref":"1 Timothy 5:2","synthesized":"The elder women as mothers; the younger as sisters, with all purity.","sources":{"KJV":{"text":"The elder women as mothers; the younger as sisters, with all purity."}},"definableWords":[],"peopleInVerse":[]},"3":{"text":"Honour widows that are widows indeed.","ref":"1 Timothy 5:3","synthesized":"Honour widows that are widows indeed.","sources":{"KJV":{"text":"Honour widows that are widows indeed."}},"definableWords":[],"peopleInVerse":[]},"4":{"text":"But if any widow have children or nephews, let them learn first to shew piety at home, and to requite their parents: for that is good and acceptable before God.","ref":"1 Timothy 5:4","synthesized":"But if any widow have children or nephews, let them learn first to shew piety at home, and to requite their parents: for that is good and acceptable before God.","sources":{"KJV":{"text":"But if any widow have children or nephews, let them learn first to shew piety at home, and to requite their parents: for that is good and acceptable before God."}},"definableWords":[],"peopleInVerse":[]},"5":{"text":"Now she that is a widow indeed, and desolate, trusteth in God, and continueth in supplications and prayers night and day.","ref":"1 Timothy 5:5","synthesized":"Now she that is a widow indeed, and desolate, trusteth in God, and continueth in supplications and prayers night and day.","sources":{"KJV":{"text":"Now she that is a widow indeed, and desolate, trusteth in God, and continueth in supplications and prayers night and day."}},"definableWords":[],"peopleInVerse":[]},"6":{"text":"But she that liveth in pleasure is dead while she liveth.","ref":"1 Timothy 5:6","synthesized":"But she that liveth in pleasure is dead while she liveth.","sources":{"KJV":{"text":"But she that liveth in pleasure is dead while she liveth."}},"definableWords":[],"peopleInVerse":[]},"7":{"text":"And these things give in charge, that they may be blameless.","ref":"1 Timothy 5:7","synthesized":"And these things give in charge, that they may be blameless.","sources":{"KJV":{"text":"And these things give in charge, that they may be blameless."}},"definableWords":[],"peopleInVerse":[]},"8":{"text":"But if any provide not for his own, and specially for those of his own house, he hath denied the faith, and is worse than an infidel.","ref":"1 Timothy 5:8","synthesized":"But if any provide not for his own, and specially for those of his own house, he hath denied the faith, and is worse than an infidel.","sources":{"KJV":{"text":"But if any provide not for his own, and specially for those of his own house, he hath denied the faith, and is worse than an infidel."}},"definableWords":[],"peopleInVerse":[]},"9":{"text":"Let not a widow be taken into the number under threescore years old, having been the wife of one man,","ref":"1 Timothy 5:9","synthesized":"Let not a widow be taken into the number under threescore years old, having been the wife of one man,","sources":{"KJV":{"text":"Let not a widow be taken into the number under threescore years old, having been the wife of one man,"}},"definableWords":[],"peopleInVerse":[]},"10":{"text":"Well reported of for good works; if she have brought up children, if she have lodged strangers, if she have washed the saints’ feet, if she have relieved the afflicted, if she have diligently followed every good work.","ref":"1 Timothy 5:10","synthesized":"Well reported of for good works; if she have brought up children, if she have lodged strangers, if she have washed the saints’ feet, if she have relieved the afflicted, if she have diligently followed every good work.","sources":{"KJV":{"text":"Well reported of for good works; if she have brought up children, if she have lodged strangers, if she have washed the saints’ feet, if she have relieved the afflicted, if she have diligently followed every good work."}},"definableWords":[],"peopleInVerse":[]},"11":{"text":"But the younger widows refuse: for when they have begun to wax wanton against Christ, they will marry;","ref":"1 Timothy 5:11","synthesized":"But the younger widows refuse: for when they have begun to wax wanton against Christ, they will marry;","sources":{"KJV":{"text":"But the younger widows refuse: for when they have begun to wax wanton against Christ, they will marry;"}},"definableWords":[],"peopleInVerse":[]},"12":{"text":"Having damnation, because they have cast off their first faith.","ref":"1 Timothy 5:12","synthesized":"Having damnation, because they have cast off their first faith.","sources":{"KJV":{"text":"Having damnation, because they have cast off their first faith."}},"definableWords":[],"peopleInVerse":[]},"13":{"text":"And withal they learn to be idle, wandering about from house to house; and not only idle, but tattlers also and busybodies, speaking things which they ought not.","ref":"1 Timothy 5:13","synthesized":"And withal they learn to be idle, wandering about from house to house; and not only idle, but tattlers also and busybodies, speaking things which they ought not.","sources":{"KJV":{"text":"And withal they learn to be idle, wandering about from house to house; and not only idle, but tattlers also and busybodies, speaking things which they ought not."}},"definableWords":[],"peopleInVerse":[]},"14":{"text":"I will therefore that the younger women marry, bear children, guide the house, give none occasion to the adversary to speak reproachfully.","ref":"1 Timothy 5:14","synthesized":"I will therefore that the younger women marry, bear children, guide the house, give none occasion to the adversary to speak reproachfully.","sources":{"KJV":{"text":"I will therefore that the younger women marry, bear children, guide the house, give none occasion to the adversary to speak reproachfully."}},"definableWords":[],"peopleInVerse":[]},"15":{"text":"For some are already turned aside after Satan.","ref":"1 Timothy 5:15","synthesized":"For some are already turned aside after Satan.","sources":{"KJV":{"text":"For some are already turned aside after Satan."}},"definableWords":[],"peopleInVerse":[]},"16":{"text":"If any man or woman that believeth have widows, let them relieve them, and let not the church be charged; that it may relieve them that are widows indeed.","ref":"1 Timothy 5:16","synthesized":"If any man or woman that believeth have widows, let them relieve them, and let not the church be charged; that it may relieve them that are widows indeed.","sources":{"KJV":{"text":"If any man or woman that believeth have widows, let them relieve them, and let not the church be charged; that it may relieve them that are widows indeed."}},"definableWords":[],"peopleInVerse":[]},"17":{"text":"Let the elders that rule well be counted worthy of double honour, especially they who labour in the word and doctrine.","ref":"1 Timothy 5:17","synthesized":"Let the elders that rule well be counted worthy of double honour, especially they who labour in the word and doctrine.","sources":{"KJV":{"text":"Let the elders that rule well be counted worthy of double honour, especially they who labour in the word and doctrine."}},"definableWords":[],"peopleInVerse":[]},"18":{"text":"For the scripture saith, Thou shalt not muzzle the ox that treadeth out the corn. And, The labourer is worthy of his reward.","ref":"1 Timothy 5:18","synthesized":"For the scripture saith, Thou shalt not muzzle the ox that treadeth out the corn. And, The labourer is worthy of his reward.","sources":{"KJV":{"text":"For the scripture saith, Thou shalt not muzzle the ox that treadeth out the corn. And, The labourer is worthy of his reward."}},"definableWords":[],"peopleInVerse":[]},"19":{"text":"Against an elder receive not an accusation, but before two or three witnesses.","ref":"1 Timothy 5:19","synthesized":"Against an elder receive not an accusation, but before two or three witnesses.","sources":{"KJV":{"text":"Against an elder receive not an accusation, but before two or three witnesses."}},"definableWords":[],"peopleInVerse":[]},"20":{"text":"Them that sin rebuke before all, that others also may fear.","ref":"1 Timothy 5:20","synthesized":"Them that sin rebuke before all, that others also may fear.","sources":{"KJV":{"text":"Them that sin rebuke before all, that others also may fear."}},"definableWords":[],"peopleInVerse":[]},"21":{"text":"I charge thee before God, and the Lord Jesus Christ, and the elect angels, that thou observe these things without preferring one before another, doing nothing by partiality.","ref":"1 Timothy 5:21","synthesized":"I charge thee before God, and the Lord Jesus Christ, and the elect angels, that thou observe these things without preferring one before another, doing nothing by partiality.","sources":{"KJV":{"text":"I charge thee before God, and the Lord Jesus Christ, and the elect angels, that thou observe these things without preferring one before another, doing nothing by partiality."}},"definableWords":[],"peopleInVerse":[]},"22":{"text":"Lay hands suddenly on no man, neither be partaker of other men’s sins: keep thyself pure.","ref":"1 Timothy 5:22","synthesized":"Lay hands suddenly on no man, neither be partaker of other men’s sins: keep thyself pure.","sources":{"KJV":{"text":"Lay hands suddenly on no man, neither be partaker of other men’s sins: keep thyself pure."}},"definableWords":[],"peopleInVerse":[]},"23":{"text":"Drink no longer water, but use a little wine for thy stomach’s sake and thine often infirmities.","ref":"1 Timothy 5:23","synthesized":"Drink no longer water, but use a little wine for thy stomach’s sake and thine often infirmities.","sources":{"KJV":{"text":"Drink no longer water, but use a little wine for thy stomach’s sake and thine often infirmities."}},"definableWords":[],"peopleInVerse":[]},"24":{"text":"Some men’s sins are open beforehand, going before to judgment; and some men they follow after.","ref":"1 Timothy 5:24","synthesized":"Some men’s sins are open beforehand, going before to judgment; and some men they follow after.","sources":{"KJV":{"text":"Some men’s sins are open beforehand, going before to judgment; and some men they follow after."}},"definableWords":[],"peopleInVerse":[]},"25":{"text":"Likewise also the good works of some are manifest beforehand; and they that are otherwise cannot be hid.","ref":"1 Timothy 5:25","synthesized":"Likewise also the good works of some are manifest beforehand; and they that are otherwise cannot be hid.","sources":{"KJV":{"text":"Likewise also the good works of some are manifest beforehand; and they that are otherwise cannot be hid."}},"definableWords":[],"peopleInVerse":[]}}},"6":{"chapter":"6","title":"1 Timothy 6","verses":{"1":{"text":"Let as many servants as are under the yoke count their own masters worthy of all honour, that the name of God and his doctrine be not blasphemed.","ref":"1 Timothy 6:1","synthesized":"Let as many servants as are under the yoke count their own masters worthy of all honour, that the name of God and his doctrine be not blasphemed.","sources":{"KJV":{"text":"Let as many servants as are under the yoke count their own masters worthy of all honour, that the name of God and his doctrine be not blasphemed."}},"definableWords":[],"peopleInVerse":[]},"2":{"text":"And they that have believing masters, let them not despise them, because they are brethren; but rather do them service, because they are faithful and beloved, partakers of the benefit. These things teach and exhort.","ref":"1 Timothy 6:2","synthesized":"And they that have believing masters, let them not despise them, because they are brethren; but rather do them service, because they are faithful and beloved, partakers of the benefit. These things teach and exhort.","sources":{"KJV":{"text":"And they that have believing masters, let them not despise them, because they are brethren; but rather do them service, because they are faithful and beloved, partakers of the benefit. These things teach and exhort."}},"definableWords":[],"peopleInVerse":[]},"3":{"text":"If any man teach otherwise, and consent not to wholesome words, even the words of our Lord Jesus Christ, and to the doctrine which is according to godliness;","ref":"1 Timothy 6:3","synthesized":"If any man teach otherwise, and consent not to wholesome words, even the words of our Lord Jesus Christ, and to the doctrine which is according to godliness;","sources":{"KJV":{"text":"If any man teach otherwise, and consent not to wholesome words, even the words of our Lord Jesus Christ, and to the doctrine which is according to godliness;"}},"definableWords":[],"peopleInVerse":[]},"4":{"text":"He is proud, knowing nothing, but doting about questions and strifes of words, whereof cometh envy, strife, railings, evil surmisings,","ref":"1 Timothy 6:4","synthesized":"He is proud, knowing nothing, but doting about questions and strifes of words, whereof cometh envy, strife, railings, evil surmisings,","sources":{"KJV":{"text":"He is proud, knowing nothing, but doting about questions and strifes of words, whereof cometh envy, strife, railings, evil surmisings,"}},"definableWords":[],"peopleInVerse":[]},"5":{"text":"Perverse disputings of men of corrupt minds, and destitute of the truth, supposing that gain is godliness: from such withdraw thyself.","ref":"1 Timothy 6:5","synthesized":"Perverse disputings of men of corrupt minds, and destitute of the truth, supposing that gain is godliness: from such withdraw thyself.","sources":{"KJV":{"text":"Perverse disputings of men of corrupt minds, and destitute of the truth, supposing that gain is godliness: from such withdraw thyself."}},"definableWords":[],"peopleInVerse":[]},"6":{"text":"But godliness with contentment is great gain.","ref":"1 Timothy 6:6","synthesized":"But godliness with contentment is great gain.","sources":{"KJV":{"text":"But godliness with contentment is great gain."}},"definableWords":[],"peopleInVerse":[]},"7":{"text":"For we brought nothing into this world, and it is certain we can carry nothing out.","ref":"1 Timothy 6:7","synthesized":"For we brought nothing into this world, and it is certain we can carry nothing out.","sources":{"KJV":{"text":"For we brought nothing into this world, and it is certain we can carry nothing out."}},"definableWords":[],"peopleInVerse":[]},"8":{"text":"And having food and raiment let us be therewith content.","ref":"1 Timothy 6:8","synthesized":"And having food and raiment let us be therewith content.","sources":{"KJV":{"text":"And having food and raiment let us be therewith content."}},"definableWords":[],"peopleInVerse":[]},"9":{"text":"But they that will be rich fall into temptation and a snare, and into many foolish and hurtful lusts, which drown men in destruction and perdition.","ref":"1 Timothy 6:9","synthesized":"But they that will be rich fall into temptation and a snare, and into many foolish and hurtful lusts, which drown men in destruction and perdition.","sources":{"KJV":{"text":"But they that will be rich fall into temptation and a snare, and into many foolish and hurtful lusts, which drown men in destruction and perdition."}},"definableWords":[],"peopleInVerse":[]},"10":{"text":"For the love of money is the root of all evil: which while some coveted after, they have erred from the faith, and pierced themselves through with many sorrows.","ref":"1 Timothy 6:10","synthesized":"For the love of money is the root of all evil: which while some coveted after, they have erred from the faith, and pierced themselves through with many sorrows.","sources":{"KJV":{"text":"For the love of money is the root of all evil: which while some coveted after, they have erred from the faith, and pierced themselves through with many sorrows."}},"definableWords":[],"peopleInVerse":[]},"11":{"text":"But thou, O man of God, flee these things; and follow after righteousness, godliness, faith, love, patience, meekness.","ref":"1 Timothy 6:11","synthesized":"But thou, O man of God, flee these things; and follow after righteousness, godliness, faith, love, patience, meekness.","sources":{"KJV":{"text":"But thou, O man of God, flee these things; and follow after righteousness, godliness, faith, love, patience, meekness."}},"definableWords":[],"peopleInVerse":[]},"12":{"text":"Fight the good fight of faith, lay hold on eternal life, whereunto thou art also called, and hast professed a good profession before many witnesses.","ref":"1 Timothy 6:12","synthesized":"Fight the good fight of faith, lay hold on eternal life, whereunto thou art also called, and hast professed a good profession before many witnesses.","sources":{"KJV":{"text":"Fight the good fight of faith, lay hold on eternal life, whereunto thou art also called, and hast professed a good profession before many witnesses."}},"definableWords":[],"peopleInVerse":[]},"13":{"text":"I give thee charge in the sight of God, who quickeneth all things, and before Christ Jesus, who before Pontius Pilate witnessed a good confession;","ref":"1 Timothy 6:13","synthesized":"I give thee charge in the sight of God, who quickeneth all things, and before Christ Jesus, who before Pontius Pilate witnessed a good confession;","sources":{"KJV":{"text":"I give thee charge in the sight of God, who quickeneth all things, and before Christ Jesus, who before Pontius Pilate witnessed a good confession;"}},"definableWords":[],"peopleInVerse":[]},"14":{"text":"That thou keep this commandment without spot, unrebukeable, until the appearing of our Lord Jesus Christ:","ref":"1 Timothy 6:14","synthesized":"That thou keep this commandment without spot, unrebukeable, until the appearing of our Lord Jesus Christ:","sources":{"KJV":{"text":"That thou keep this commandment without spot, unrebukeable, until the appearing of our Lord Jesus Christ:"}},"definableWords":[],"peopleInVerse":[]},"15":{"text":"Which in his times he shall shew, who is the blessed and only Potentate, the King of kings, and Lord of lords;","ref":"1 Timothy 6:15","synthesized":"Which in his times he shall shew, who is the blessed and only Potentate, the King of kings, and Lord of lords;","sources":{"KJV":{"text":"Which in his times he shall shew, who is the blessed and only Potentate, the King of kings, and Lord of lords;"}},"definableWords":[],"peopleInVerse":[]},"16":{"text":"Who only hath immortality, dwelling in the light which no man can approach unto; whom no man hath seen, nor can see: to whom be honour and power everlasting. Amen.","ref":"1 Timothy 6:16","synthesized":"Who only hath immortality, dwelling in the light which no man can approach unto; whom no man hath seen, nor can see: to whom be honour and power everlasting. Amen.","sources":{"KJV":{"text":"Who only hath immortality, dwelling in the light which no man can approach unto; whom no man hath seen, nor can see: to whom be honour and power everlasting. Amen."}},"definableWords":[],"peopleInVerse":[]},"17":{"text":"Charge them that are rich in this world, that they be not highminded, nor trust in uncertain riches, but in the living God, who giveth us richly all things to enjoy;","ref":"1 Timothy 6:17","synthesized":"Charge them that are rich in this world, that they be not highminded, nor trust in uncertain riches, but in the living God, who giveth us richly all things to enjoy;","sources":{"KJV":{"text":"Charge them that are rich in this world, that they be not highminded, nor trust in uncertain riches, but in the living God, who giveth us richly all things to enjoy;"}},"definableWords":[],"peopleInVerse":[]},"18":{"text":"That they do good, that they be rich in good works, ready to distribute, willing to communicate;","ref":"1 Timothy 6:18","synthesized":"That they do good, that they be rich in good works, ready to distribute, willing to communicate;","sources":{"KJV":{"text":"That they do good, that they be rich in good works, ready to distribute, willing to communicate;"}},"definableWords":[],"peopleInVerse":[]},"19":{"text":"Laying up in store for themselves a good foundation against the time to come, that they may lay hold on eternal life.","ref":"1 Timothy 6:19","synthesized":"Laying up in store for themselves a good foundation against the time to come, that they may lay hold on eternal life.","sources":{"KJV":{"text":"Laying up in store for themselves a good foundation against the time to come, that they may lay hold on eternal life."}},"definableWords":[],"peopleInVerse":[]},"20":{"text":"O Timothy, keep that which is committed to thy trust, avoiding profane and vain babblings, and oppositions of science falsely so called:","ref":"1 Timothy 6:20","synthesized":"O Timothy, keep that which is committed to thy trust, avoiding profane and vain babblings, and oppositions of science falsely so called:","sources":{"KJV":{"text":"O Timothy, keep that which is committed to thy trust, avoiding profane and vain babblings, and oppositions of science falsely so called:"}},"definableWords":[],"peopleInVerse":[]},"21":{"text":"Which some professing have erred concerning the faith. Grace be with thee. Amen.","ref":"1 Timothy 6:21","synthesized":"Which some professing have erred concerning the faith. Grace be with thee. Amen.","sources":{"KJV":{"text":"Which some professing have erred concerning the faith. Grace be with thee. Amen."}},"definableWords":[],"peopleInVerse":[]}}}};